UPDATE products p
p.name = #{name}, p.price = #{price}, p.stock = #{stock}, p.category = #{category}, p.status = #{status},
WHERE p.id = #{id}

UPDATE products
SET admin_status = #{adminStatus}
WHERE id = #{shopId}

UPDATE product_details pd
pd.description = #{description}, pd.specification = #{specification}, pd.image_urls = #{imageUrls}, pd.label = #{label},
WHERE pd.product_id = #{id}

mapper.select:
SELECT p.id, p.name, p.price, p.stock, p.merchant_id as merchantId, p.status, p.category, p.created_at as createdAt, p.admin_status as adminStatus, pd.image_urls as imageUrls FROM products p LEFT JOIN product_details pd ON p.id = pd.product_id
AND p.name LIKE CONCAT('%', #{name}, '%')
AND p.merchant_id = #{merchantId}
AND p.category = #{category}
ORDER BY p.created_at DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM products p


        AND p.name LIKE CONCAT('%', #{name}, '%')


        AND p.merchant_id = #{merchantId}


        AND p.category = #{category}
